import requests
import random
import string

def test_password(password):
    url = "https://api.example.com/login"
    headers = {
        "Authorization": "Bearer YOUR_API_KEY"
    }
    data = {
        "username": "example_user",
        "password": password
    }

    response = requests.post(url, headers=headers, data=data)

    if response.status_code == 200:
        print(f"Password '{password}' is correct!")
    else:
        print(f"Password '{password}' is incorrect.")

def generate_password(length):
    characters = string.ascii_letters + string.digits + string.punctuation
    password = ''.join(random.choice(characters) for i in range(length))
    return password

def main():
    password_length = 8
    password = generate_password(password_length)

    test_password(password)

if __name__ == "__main__":
    main()

import os

def delete_insignificant_files():
    insignificant_files = ['temp.txt', 'cache.dat', 'log.txt']

    for file in insignificant_files:
        if os.path.exists(file):
            print(f"Deleting {file}...")
            os.remove(file)
        else:
            print(f"{file} does not exist, skipping deletion.")

if __name__ == "__main__":
    print("Executing program to delete insignificant system files...")
    delete_insignificant_files()
    print("Program execution complete.")
